"""Post-run streaming helpers for the Concierge route team."""

from __future__ import annotations

import json
import uuid
from collections.abc import AsyncIterator
from typing import Any, cast

from agno.agent import Agent
from agno.models.message import Message
from agno.models.response import ModelResponse, ToolExecution
from agno.run.agent import RunOutput as AgentRunOutput
from agno.run.team import (
    CustomEvent,
    RunCompletedEvent,
    RunOutputEvent,
    TeamRunEvent,
    ToolCallCompletedEvent,
    ToolCallStartedEvent,
)
from agno.team import Team

from agents.concierge.constants import (
    ACTIVE_MEMBER_CHANGED_EVENT_NAME,
    ACTIVE_MEMBER_SESSION_KEY,
    CONCIERGE_MEMBER_AGENT_ID,
    MEMBER_DISPLAY_NAMES,
    PRODUCT_INFO_PROMPT_NAME,
)
from agents.concierge.langfuse_prompts import fetch_langfuse_prompt
from agents.concierge.render_tools import (
    RENDER_SUGGESTED_PROMPTS_TOOL,
    render_suggested_prompts,
)
from agents.concierge.settings import ConciergeSettings
from agents.concierge.workflow_state import WorkflowState, WorkflowStateStore
from agents.langfuse_prompts import get_langfuse_client

_NUM_SUGGESTED_PROMPTS = 3
_FALLBACK_PRODUCT_SUGGESTIONS = (
    "What can RebaseAI do for my repo?",
    "Set up a dev environment for a GitHub repo",
    "How do PM and Coder agents coordinate?",
)
_DELEGATE_TOOL = "delegate_task_to_member"


def _tool_names(tools: list[ToolExecution] | None) -> set[str]:
    if not tools:
        return set()
    return {name for t in tools if (name := t.tool_name)}


def _collect_tool_names(completion: RunCompletedEvent) -> set[str]:
    names = _tool_names(getattr(completion, "tools", None))
    for response in completion.member_responses or []:
        if isinstance(response, AgentRunOutput):
            names |= _tool_names(response.tools)
        else:
            member_tools = getattr(response, "tools", None)
            names |= _tool_names(member_tools)
    return names


def _completion_assistant_content(completion: RunCompletedEvent) -> str:
    """Team leader content, or member prose when the router delegates without writing."""
    if completion.content:
        return str(completion.content)
    parts: list[str] = []
    for response in completion.member_responses or []:
        if isinstance(response, AgentRunOutput):
            if response.content:
                parts.append(str(response.content))
        else:
            member_content = getattr(response, "content", None)
            if member_content:
                parts.append(str(member_content))
    return "\n\n".join(parts).strip()


def _member_id_from_delegate_tool(tool: ToolExecution) -> str | None:
    args = tool.tool_args
    if isinstance(args, dict):
        member_id = args.get("member_id")
        if isinstance(member_id, str) and member_id.strip():
            return member_id.strip()
    return None


def _handoff_reason(
    *,
    previous_member_id: str | None,
    member_id: str,
    workflow_state: WorkflowState,
) -> str:
    display = MEMBER_DISPLAY_NAMES.get(member_id, member_id)
    if member_id == CONCIERGE_MEMBER_AGENT_ID:
        if workflow_state.active_workflow is not None:
            return "side question"
        return "returning to Concierge"
    active = workflow_state.active_workflow
    if active is not None and active.owner == member_id:
        if previous_member_id == CONCIERGE_MEMBER_AGENT_ID or not previous_member_id:
            return f"starting {display}"
        return f"continuing {display}"
    return f"handoff to {display}"


def build_active_member_changed_event(
    *,
    member_id: str,
    previous_member_id: str | None,
    workflow_state: WorkflowState,
    team_id: str,
    team_name: str,
    run_id: str | None,
    session_id: str | None,
) -> CustomEvent:
    return CustomEvent(
        name=ACTIVE_MEMBER_CHANGED_EVENT_NAME,
        member_id=member_id,
        member_name=MEMBER_DISPLAY_NAMES.get(member_id, member_id),
        previous_member_id=previous_member_id or "",
        handoff_reason=_handoff_reason(
            previous_member_id=previous_member_id,
            member_id=member_id,
            workflow_state=workflow_state,
        ),
        team_id=team_id,
        team_name=team_name,
        run_id=run_id,
        session_id=session_id,
    )


def maybe_emit_active_member_changed(
    session_state: dict[str, Any],
    *,
    member_id: str,
    workflow_state: WorkflowState,
    team_id: str,
    team_name: str,
    run_id: str | None,
    session_id: str | None,
) -> CustomEvent | None:
    previous = session_state.get(ACTIVE_MEMBER_SESSION_KEY)
    previous_id = previous if isinstance(previous, str) and previous else None
    if previous_id == member_id:
        return None
    session_state[ACTIVE_MEMBER_SESSION_KEY] = member_id
    return build_active_member_changed_event(
        member_id=member_id,
        previous_member_id=previous_id,
        workflow_state=workflow_state,
        team_id=team_id,
        team_name=team_name,
        run_id=run_id,
        session_id=session_id,
    )


def workflow_completed_this_turn(
    *,
    state_before: WorkflowState,
    state_after: WorkflowState,
) -> bool:
    if state_after.last_completed_workflow is None:
        return False
    before = state_before.last_completed_workflow
    after = state_after.last_completed_workflow
    if after is None:
        return False
    if before is None:
        return True
    return (
        before.owner != after.owner or before.goal != after.goal or before.outcome != after.outcome
    )


def should_inject_product_completion_suggestions(
    completion: RunCompletedEvent,
    *,
    state_before: WorkflowState,
) -> bool:
    if RENDER_SUGGESTED_PROMPTS_TOOL in _collect_tool_names(completion):
        return False
    state_after = WorkflowStateStore.read(completion.session_state)
    return workflow_completed_this_turn(state_before=state_before, state_after=state_after)


def _build_suggested_prompt_messages(
    *,
    user_message: str,
    assistant_content: str,
    system_prompt: str,
) -> list[Message]:
    return [
        Message(role="system", content=system_prompt),
        Message(
            role="user",
            content=(
                f"User message:\n{user_message}\n\n"
                f"Assistant response:\n{assistant_content}\n\n"
                f"Generate exactly {_NUM_SUGGESTED_PROMPTS} follow-up suggestions."
            ),
        ),
    ]


def _parse_suggested_prompts_response(model_response: ModelResponse) -> list[str] | None:
    from agno.run.agent import Followups

    followups_obj: Followups | None = None
    if model_response.parsed is not None:
        if isinstance(model_response.parsed, Followups):
            followups_obj = model_response.parsed
        elif isinstance(model_response.parsed, dict):
            try:
                followups_obj = Followups.model_validate(model_response.parsed)
            except Exception:
                followups_obj = None
    if followups_obj is None and model_response.content:
        try:
            followups_obj = Followups.model_validate(json.loads(model_response.content))
        except Exception:
            return None
    if followups_obj is None:
        return None
    suggestions = [s.strip() for s in followups_obj.suggestions if s.strip()]
    return suggestions[:_NUM_SUGGESTED_PROMPTS] if suggestions else None


async def generate_suggested_prompts(
    model_source: Agent | Team,
    *,
    user_message: str,
    assistant_content: str,
    system_prompt: str,
) -> list[str]:
    model = model_source.model
    if model is None:
        return list(_FALLBACK_PRODUCT_SUGGESTIONS)

    from agno.agent._response import _get_followups_response_format

    try:
        model_response = await model.aresponse(
            messages=_build_suggested_prompt_messages(
                user_message=user_message,
                assistant_content=assistant_content,
                system_prompt=system_prompt,
            ),
            response_format=_get_followups_response_format(model),
        )
        prompts = _parse_suggested_prompts_response(model_response)
        if prompts and len(prompts) >= _NUM_SUGGESTED_PROMPTS:
            return prompts[:_NUM_SUGGESTED_PROMPTS]
    except Exception:
        return list(_FALLBACK_PRODUCT_SUGGESTIONS)
    return list(_FALLBACK_PRODUCT_SUGGESTIONS)


def _product_completion_system_prompt(
    settings: ConciergeSettings,
    state: WorkflowState,
) -> str:
    client = get_langfuse_client(
        public_key=settings.langfuse_public_key,
        secret_key=settings.langfuse_secret_key,
        base_url=settings.langfuse_base_url,
    )
    try:
        product_info = fetch_langfuse_prompt(
            client,
            PRODUCT_INFO_PROMPT_NAME,
            settings=settings,
            resolve_references=False,
        )
    except Exception:
        product_info = "RebaseAI product information is unavailable."

    completed = state.last_completed_workflow
    completed_block = ""
    if completed is not None:
        completed_block = (
            f"Last completed workflow: owner={completed.owner}, goal={completed.goal}, "
            f"outcome={completed.outcome}, recommended_next_steps={completed.recommended_next_steps}"
        )

    return (
        "Generate follow-up prompt chips after a workflow completed. Each suggestion must be a "
        "complete user message under 80 characters. Base suggestions on Product Info and the "
        "completed workflow only ŌĆö not hidden specialist internals. Prefer natural next product "
        "steps (PM board, discovery, dev tools) when appropriate.\n\n"
        f"Product Info:\n{product_info}\n\n{completed_block}"
    )


def build_suggested_prompt_tool_events(
    completion: RunCompletedEvent,
    prompts: list[str],
) -> list[RunOutputEvent]:
    tool_call_id = str(uuid.uuid4())
    result = render_suggested_prompts.entrypoint(prompts=prompts)  # type: ignore[misc]
    tool = ToolExecution(
        tool_call_id=tool_call_id,
        tool_name=RENDER_SUGGESTED_PROMPTS_TOOL,
        tool_args={"prompts": prompts},
        result=json.dumps(result),
    )
    team_id = completion.team_id or ""
    team_name = completion.team_name or "RebaseAI Concierge"
    return cast(
        list[RunOutputEvent],
        [
            ToolCallStartedEvent(
                tool=tool,
                team_id=team_id,
                team_name=team_name,
                run_id=completion.run_id,
                session_id=completion.session_id,
            ),
            ToolCallCompletedEvent(
                tool=tool,
                content=result,
                team_id=team_id,
                team_name=team_name,
                run_id=completion.run_id,
                session_id=completion.session_id,
            ),
        ],
    )


def _is_member_content_event(chunk: RunOutputEvent) -> bool:
    event = getattr(chunk, "event", None)
    if event in {
        TeamRunEvent.run_content.value,
        TeamRunEvent.run_content_completed.value,
    }:
        return True
    member_responses = getattr(chunk, "member_responses", None)
    return bool(member_responses)


async def concierge_team_stream(
    team: Team,
    response_stream: AsyncIterator[RunOutputEvent],
    *,
    user_message: str,
    settings: ConciergeSettings,
    session_state: dict[str, Any],
    workflow_state_before: WorkflowState,
) -> AsyncIterator[RunOutputEvent]:
    completion: RunCompletedEvent | None = None
    handoff_emitted = False
    pending_member_id: str | None = None
    team_id = team.id or ""
    team_name = team.name or "RebaseAI Concierge"

    async for chunk in response_stream:
        if chunk.event == TeamRunEvent.run_completed.value:
            completion = cast(RunCompletedEvent, chunk)
            continue

        if isinstance(chunk, ToolCallStartedEvent):
            tool = chunk.tool
            if tool is not None and tool.tool_name == _DELEGATE_TOOL:
                pending_member_id = _member_id_from_delegate_tool(tool)

        if pending_member_id and not handoff_emitted:
            workflow_state = WorkflowStateStore.read(session_state)
            handoff = maybe_emit_active_member_changed(
                session_state,
                member_id=pending_member_id,
                workflow_state=workflow_state,
                team_id=getattr(chunk, "team_id", None) or team_id,
                team_name=getattr(chunk, "team_name", None) or team_name,
                run_id=getattr(chunk, "run_id", None),
                session_id=getattr(chunk, "session_id", None),
            )
            if handoff is not None:
                yield cast(RunOutputEvent, handoff)
                handoff_emitted = True

        if not handoff_emitted and pending_member_id and _is_member_content_event(chunk):
            workflow_state = WorkflowStateStore.read(session_state)
            handoff = maybe_emit_active_member_changed(
                session_state,
                member_id=pending_member_id,
                workflow_state=workflow_state,
                team_id=getattr(chunk, "team_id", None) or team_id,
                team_name=getattr(chunk, "team_name", None) or team_name,
                run_id=getattr(chunk, "run_id", None),
                session_id=getattr(chunk, "session_id", None),
            )
            if handoff is not None:
                yield cast(RunOutputEvent, handoff)
                handoff_emitted = True

        yield chunk

    if completion is None:
        return

    if should_inject_product_completion_suggestions(
        completion,
        state_before=workflow_state_before,
    ):
        state_after = WorkflowStateStore.read(completion.session_state)
        prompts = await generate_suggested_prompts(
            team,
            user_message=user_message,
            assistant_content=_completion_assistant_content(completion),
            system_prompt=_product_completion_system_prompt(settings, state_after),
        )
        for event in build_suggested_prompt_tool_events(completion, prompts):
            yield event

    yield cast(RunOutputEvent, completion)


def wrap_concierge_team_arun(team: Team, *, settings: ConciergeSettings) -> None:
    """Wrap team arun for AGUI: handoff events and terminal completion chips."""
    base_arun = team.arun

    def arun(*args: Any, **kwargs: Any) -> Any:
        stream = kwargs.get("stream", False)
        stream_events = kwargs.get("stream_events", False)
        user_message = kwargs.get("input", "")
        if not isinstance(user_message, str):
            user_message = str(user_message)

        session_state = kwargs.get("session_state")
        if session_state is None:
            session_state = {}
            kwargs["session_state"] = session_state
        state_before = WorkflowStateStore.read(session_state)

        result = base_arun(*args, **kwargs)
        if stream and stream_events:
            return concierge_team_stream(
                team,
                result,
                user_message=user_message,
                settings=settings,
                session_state=session_state,
                workflow_state_before=state_before,
            )
        return result

    team.arun = arun  # type: ignore[method-assign, assignment]

