    with patch("agents.concierge.prompt_composer._fetch_prompt_text", side_effect=fake_fetch):
        body = instructions(session_state=session)

    assert specialist_stage_prompt("discovery", "running") in fetched
    assert "body:rebaseai/discovery/stage/running" in body


def test_specialist_stage_fallback_to_idle() -> None:
    cache = SessionInstructionsCache(max_entries=4)
    calls: list[str] = []

    def fake_fetch(_settings, name: str, **kwargs) -> str:
        calls.append(name)
        if name == specialist_stage_prompt("discovery", "unknown"):
            raise RuntimeError("missing")
        return f"body:{name}"

    session = {
        WorkflowStateStore.session_key: {
            "active_workflow": {
                "owner": "discovery-agent",
                "status": "active",
                "goal": "g",
                "stage": "unknown",
            }
        }
    }
    instructions = compose_specialist_instructions(
        owner_id="discovery-agent",
